1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell with no neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill cells with only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
19	    expect(result).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
20	  });
21	  it("should keep a live cell alive when it has 2 or 3 neighbors (survival)", () => {
22	    const result = nextGeneration([[0, 1], [1, 1], [2, 1]]);
23	    expect(result).toEqual([[1, 0], [1, 1], [1, 2]]);
24	  });
25	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
26	    // Plus/cross pattern: center cell (1,1) has 4 live neighbors -> dies
27	    const input: [number, number][] = [[0, 1], [1, 0], [1, 1], [1, 2], [2, 1]];
28	    const result = nextGeneration(input);
29	    // Center (1,1) has 4 neighbors -> dies (overpopulation)
30	    // Each arm cell has 1-2 neighbors from the pattern, plus dead cells may come alive
31	    // Let's verify (1,1) is NOT in the result
32	    expect(result).not.toContainEqual([1, 1]);
33	  });
34	  it("should keep a block pattern unchanged (still life)", () => {
35	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
36	    const result = nextGeneration(block);
37	    expect(result).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
38	  });
