1	function neighborsOf(x: number, y: number): [number, number][] {
2	  const result: [number, number][] = [];
3	  for (let dx = -1; dx <= 1; dx++) {
4	    for (let dy = -1; dy <= 1; dy++) {
5	      if (dx === 0 && dy === 0) continue;
6	      result.push([x + dx, y + dy]);
7	    }
8	  }
9	  return result;
10	}
11	
12	function toKey(x: number, y: number): string {
13	  return `${x},${y}`;
14	}
15	
16	export function nextGeneration(cells: [number, number][]): [number, number][] {
17	  const liveSet = new Set(cells.map(([x, y]) => toKey(x, y)));
18	
19	  const candidates = new Set<string>();
20	  for (const [x, y] of cells) {
21	    candidates.add(toKey(x, y));
22	    for (const [nx, ny] of neighborsOf(x, y)) {
23	      candidates.add(toKey(nx, ny));
24	    }
25	  }
26	
27	  const result: [number, number][] = [];
28	  for (const key of candidates) {
29	    const [x, y] = key.split(",").map(Number) as [number, number];
30	    const liveNeighborCount = neighborsOf(x, y).filter(([nx, ny]) =>
31	      liveSet.has(toKey(nx, ny))
32	    ).length;
33	    const alive = liveSet.has(key);
34	    const shouldLive =
35	      liveNeighborCount === 3 || (alive && liveNeighborCount === 2);
36	    if (shouldLive) {
37	      result.push([x, y]);
38	    }
39	  }
40	
41	  result.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
42	  return result;
43	}
